import{c as e,Q as r,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"延伸閱讀與參考資料","description":"","frontmatter":{},"headers":[],"relativePath":"resources/reference/index.md","filePath":"resources/reference/index.md","lastUpdated":1779796674000}'),o={name:"resources/reference/index.md"};function d(s,t,l,i,h,c){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="延伸閱讀與參考資料" tabindex="-1">延伸閱讀與參考資料 <a class="header-anchor" href="#延伸閱讀與參考資料" aria-label="Permalink to &quot;延伸閱讀與參考資料&quot;">​</a></h1><p>篩選標準：只收錄能<strong>直接解釋 Harness 機制</strong>的文章。Harness 在這裡指模型外部的運行系統，包括 agent loop、工具執行、沙箱、狀態、上下文、驗證、終止條件、控制平面和觀測反饋。不收錄泛泛的 prompt engineering 或 agent 框架介紹。</p><h2 id="核心三篇-必讀" tabindex="-1">核心三篇（必讀） <a class="header-anchor" href="#核心三篇-必讀" aria-label="Permalink to &quot;核心三篇（必讀）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>日期</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://openai.com/index/harness-engineering/" target="_blank" rel="noreferrer">OpenAI: Harness engineering: leveraging Codex in an agent-first world</a></td><td>2026-02-11</td><td>agent-first 倉庫、repo-local context、custom lint、結構性 guardrail</td></tr><tr><td><a href="https://www.anthropic.com/engineering/effective-harnesses-for-long-running-agents" target="_blank" rel="noreferrer">Anthropic: Effective harnesses for long-running agents</a></td><td>2025-11-26</td><td>initializer agent、coding agent、feature list、progress log、跨上下文窗口交接</td></tr><tr><td><a href="https://www.anthropic.com/engineering/harness-design-long-running-apps" target="_blank" rel="noreferrer">Anthropic: Harness design for long-running application development</a></td><td>2026-03-24</td><td>planner / generator / evaluator 三角色、context reset、harness 簡化和組件過期</td></tr></tbody></table><h2 id="harness-工程實踐" tabindex="-1">Harness 工程實踐 <a class="header-anchor" href="#harness-工程實踐" aria-label="Permalink to &quot;Harness 工程實踐&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://www.langchain.com/blog/improving-deep-agents-with-harness-engineering" target="_blank" rel="noreferrer">LangChain: Improving Deep Agents with harness engineering</a></td><td>只改 harness（system prompt、tools、middleware、tracing、self-verification），讓 coding agent 從 Top 30 進到 Top 5</td></tr><tr><td><a href="https://martinfowler.com/articles/harness-engineering.html" target="_blank" rel="noreferrer">Thoughtworks / Martin Fowler: Harness engineering for coding agent users</a></td><td>把 harness 拆成 feedforward guides 和 feedback sensors；deterministic vs inferential controls</td></tr><tr><td><a href="https://humanlayer.dev/articles/harness-engineering-for-coding-agents/" target="_blank" rel="noreferrer">HumanLayer: Skill Issue — Harness Engineering for Coding Agents</a></td><td>CLAUDE.md + hooks 的具體實踐；Ratchet 原則</td></tr><tr><td><a href="https://cursor.com/blog/continually-improving-agent-harness" target="_blank" rel="noreferrer">Cursor: Continually improving our agent harness</a></td><td>把 harness 當成持續迭代的產品系統；離線評估 + 線上指標</td></tr></tbody></table><h2 id="context-管理" tabindex="-1">Context 管理 <a class="header-anchor" href="#context-管理" aria-label="Permalink to &quot;Context 管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://www.langchain.com/blog/context-management-for-deepagents" target="_blank" rel="noreferrer">LangChain: Context Management for Deep Agents</a></td><td>filesystem offloading、tool-call truncation、summarization、targeted evals</td></tr><tr><td><a href="https://www.trychroma.com/blog/context-rot" target="_blank" rel="noreferrer">Chroma: Context Rot Research</a></td><td>18 個模型的量化衰退數據；NIAH benchmark；1M context window 的虛假安全感</td></tr></tbody></table><h2 id="agent-loop-機制" tabindex="-1">Agent Loop 機制 <a class="header-anchor" href="#agent-loop-機制" aria-label="Permalink to &quot;Agent Loop 機制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://openai.com/index/unrolling-the-codex-agent-loop/" target="_blank" rel="noreferrer">OpenAI: Unrolling the Codex agent loop</a></td><td>Codex runtime harness 的核心循環、工具調用、上下文增長和終止狀態</td></tr><tr><td><a href="https://simonwillison.net/2025/Sep/30/designing-agentic-loops/" target="_blank" rel="noreferrer">Simon Willison: Designing agentic loops</a></td><td>Agentic loop 設計原則；測試套件是 loop 基礎</td></tr></tbody></table><h2 id="評估與驗證" tabindex="-1">評估與驗證 <a class="header-anchor" href="#評估與驗證" aria-label="Permalink to &quot;評估與驗證&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://www.anthropic.com/engineering/demystifying-evals-for-ai-agents" target="_blank" rel="noreferrer">Anthropic: Demystifying evals for AI agents</a></td><td>評估 agent 時評的是 model + harness；evaluation harness 與 agent harness 的區別</td></tr><tr><td><a href="https://eugeneyan.com/writing/llm-patterns/" target="_blank" rel="noreferrer">Eugene Yan: LLM Patterns</a></td><td>Evals pattern 是生產系統的基石</td></tr></tbody></table><h2 id="企業級-harness" tabindex="-1">企業級 Harness <a class="header-anchor" href="#企業級-harness" aria-label="Permalink to &quot;企業級 Harness&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://stripe.dev/blog/minions-stripes-one-shot-end-to-end-coding-agents" target="_blank" rel="noreferrer">Stripe: Minions — one-shot end-to-end coding agents</a></td><td>devbox 隔離、custom agent harness、blueprints 狀態機、規則檔案、MCP tool curation、安全控制</td></tr><tr><td><a href="https://www.anthropic.com/engineering/building-c-compiler" target="_blank" rel="noreferrer">Anthropic: Building a C compiler with parallel Claudes</a></td><td>並行 agent 團隊、任務鎖、git 同步、容器隔離</td></tr><tr><td><a href="https://www.anthropic.com/engineering/april-23-postmortem" target="_blank" rel="noreferrer">Anthropic: April 23 Postmortem</a></td><td>reasoning effort、context pruning、system prompt 都屬於 harness 變更，且需要回歸治理</td></tr></tbody></table><h2 id="agent-架構理論" tabindex="-1">Agent 架構理論 <a class="header-anchor" href="#agent-架構理論" aria-label="Permalink to &quot;Agent 架構理論&quot;">​</a></h2><table tabindex="0"><thead><tr><th>論文</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://lilianweng.github.io/posts/2023-06-23-agent/" target="_blank" rel="noreferrer">Lilian Weng: LLM-powered Autonomous Agents</a></td><td>ReAct、Memory 架構、工具使用的全面介紹</td></tr><tr><td><a href="https://arxiv.org/abs/2309.02427" target="_blank" rel="noreferrer">CoALA: Cognitive Architectures for Language Agents</a></td><td>認知架構分類框架</td></tr></tbody></table><h2 id="claude-md-與-karpathy-規則" tabindex="-1">CLAUDE.md 與 Karpathy 規則 <a class="header-anchor" href="#claude-md-與-karpathy-規則" aria-label="Permalink to &quot;CLAUDE.md 與 Karpathy 規則&quot;">​</a></h2><p>Andrej Karpathy 的 CLAUDE.md（Skills file）對 AI 輔助開發的影響深遠，以下是核心文章：</p><table tabindex="0"><thead><tr><th>文章</th><th>核心貢獻</th></tr></thead><tbody><tr><td><a href="https://agentpedia.io/karpathy-skills-file-complete-guide" target="_blank" rel="noreferrer">Agentpedia: Karpathy&#39;s CLAUDE.md Skills File — The Complete Guide</a></td><td>完整分析 Karpathy 的四條核心規則</td></tr><tr><td><a href="https://gist.github.com/karpathy/2c4ece47fbd90eb066b8e0d756f7cd00" target="_blank" rel="noreferrer">Andrej Karpathy: LLM Wiki — A Knowledge Management Pattern</a></td><td>LLM wiki 的 knowledge management 模式</td></tr></tbody></table><p><strong>Karpathy 的四條核心原則</strong>：</p><ol><li><strong>不讓 AI 刪程式碼</strong>：除非有明確理由，否則刪除是破壞性的</li><li><strong>測試要跑起來</strong>：能執行的測試才是真正的驗證</li><li><strong>不改無關的東西</strong>：範圍控制是 agent 最容易失控的地方</li><li><strong>對話後更新規則</strong>：把發現的知識沉澱到 CLAUDE.md</li></ol><h2 id="ratchet-原則的來源" tabindex="-1">Ratchet 原則的來源 <a class="header-anchor" href="#ratchet-原則的來源" aria-label="Permalink to &quot;Ratchet 原則的來源&quot;">​</a></h2><p>Mitchell Hashimoto 原話：</p><blockquote><p>「Anytime you find an agent makes a mistake, you take the time to engineer a solution such that the agent never makes that mistake again.」</p></blockquote><p>Addy Osmani 的延伸（<a href="https://addyosmani.com/blog/ai-assisted-coding/" target="_blank" rel="noreferrer">AI-assisted coding: building better LLM habits</a>）：</p><blockquote><p>「Every line in a good AGENTS.md should be traceable back to a specific thing that went wrong.」</p></blockquote><p>這是貫穿本課程的核心工程哲學：Harness 不是預先設計的，而是從失敗中沉澱出來的。</p><h2 id="claude-code-官方文件索引" tabindex="-1">Claude Code 官方文件索引 <a class="header-anchor" href="#claude-code-官方文件索引" aria-label="Permalink to &quot;Claude Code 官方文件索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主題</th><th>URL</th></tr></thead><tbody><tr><td>快速開始</td><td><a href="https://code.claude.com/docs" target="_blank" rel="noreferrer">https://code.claude.com/docs</a></td></tr><tr><td>Memory（CLAUDE.md + Auto Memory）</td><td><a href="https://code.claude.com/docs/en/memory" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/memory</a></td></tr><tr><td>Hooks</td><td><a href="https://code.claude.com/docs/en/hooks" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/hooks</a></td></tr><tr><td>Sandboxing</td><td><a href="https://code.claude.com/docs/en/sandboxing" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/sandboxing</a></td></tr><tr><td>Permissions</td><td><a href="https://code.claude.com/docs/en/permissions" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/permissions</a></td></tr><tr><td>Sub-Agents</td><td><a href="https://code.claude.com/docs/en/sub-agents" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/sub-agents</a></td></tr><tr><td>MCP</td><td><a href="https://code.claude.com/docs/en/mcp" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/mcp</a></td></tr><tr><td>Skills</td><td><a href="https://code.claude.com/docs/en/skills" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/skills</a></td></tr><tr><td>How Claude Code Works</td><td><a href="https://code.claude.com/docs/en/how-claude-code-works" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/how-claude-code-works</a></td></tr><tr><td>Common Workflows</td><td><a href="https://code.claude.com/docs/en/common-workflows" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/common-workflows</a></td></tr></tbody></table>',29)])])}const m=e(o,[["render",d]]);export{p as __pageData,m as default};
